// Plan the sheets we need
const spreadsheetId = $('Config').first().json.spreadsheetId;
const existing = ($json.sheets || []).map(s => s.properties.title);

const REQUIRED = {
  source_registry: ['source_id','name','url','type','tier','enabled','topic_scope','trust_score','notes'],
  fallback_library: ['fallback_id','category','title','angle','target','priority','enabled'],
  run_logs: ['run_id','run_date','mode','sources_total','sources_failed','raw_items_count','deduped_count','selected_count','telegram_status','notes','started_at','ended_at'],
  ranked_items_history: ['run_id','item_id','title','url','source_name','published_at','primary_topic','candidate_score','publishable_score','confidence','selected_yes_no','selection_reason'],
  content_history: ['content_id','run_id','item_id','mode','platform_pair','status','confidence_label','instagram_hook','instagram_script','instagram_caption','instagram_cta','linkedin_post','source_name','source_url','prompt_version'],
  publication_feedback: ['content_id','published_yes_no','published_date','platform','views','likes','comments','saves','notes']
};

const missing = Object.keys(REQUIRED).filter(t => !existing.includes(t));
const addRequests = missing.map(title => ({ addSheet: { properties: { title } } }));

// Source registry seed
const SOURCE_ROWS = [
  ['src_openai','OpenAI News','https://openai.com/news/rss.xml','rss','tier1','true','generative_ai|business_ai','0.95','Official'],
  ['src_anthropic','Anthropic News','https://www.anthropic.com/news','html','tier1','true','generative_ai|business_ai','0.95','Official – HTML scrape'],
  ['src_google_ai','Google AI Blog','https://blog.google/technology/ai/rss/','rss','tier1','true','generative_ai|business_ai','0.9','Official'],
  ['src_deepmind','Google DeepMind Blog','https://deepmind.google/blog/rss.xml','rss','tier1','true','generative_ai','0.9','Official'],
  ['src_hf','Hugging Face Blog','https://huggingface.co/blog/feed.xml','rss','tier1','true','generative_ai','0.85','Official'],
  ['src_ms_ai','Microsoft AI Blog','https://blogs.microsoft.com/ai/feed/','rss','tier1','true','business_ai','0.85','Official'],
  ['src_meta_ai','Meta AI Blog','https://ai.meta.com/blog/rss/','rss','tier1','true','generative_ai','0.85','Official'],
  ['src_nvidia','NVIDIA Blog','https://blogs.nvidia.com/feed/','rss','tier1','true','generative_ai','0.8','Official'],
  ['src_mistral','Mistral AI News','https://mistral.ai/news/','html','tier1','true','generative_ai','0.8','Official – HTML'],
  ['src_techcrunch_ai','TechCrunch AI','https://techcrunch.com/category/artificial-intelligence/feed/','rss','tier2','true','business_ai','0.75','Trusted media'],
  ['src_venturebeat','VentureBeat AI','https://venturebeat.com/category/ai/feed/','rss','tier2','true','business_ai','0.75','Trusted media'],
  ['src_the_decoder','The Decoder','https://the-decoder.com/feed/','rss','tier2','true','generative_ai|business_ai','0.7','Trusted media'],
  ['src_theverge_ai','The Verge AI','https://www.theverge.com/rss/ai-artificial-intelligence/index.xml','rss','tier2','true','generative_ai|business_ai','0.7','Trusted media'],
  ['src_mit_tech','MIT Tech Review AI','https://www.technologyreview.com/feed/','rss','tier2','true','generative_ai|business_ai','0.8','Trusted media']
];

// Fallback library seed
const FALLBACK_ROWS = [
  ['fb_001','evergreen','Come capire se una news AI conta davvero per un business','Framework valutativo per filtrare segnale vs rumore','sme|entrepreneur','high','true'],
  ['fb_002','evergreen','3 segnali per distinguere hype da impatto reale','Checklist anti-hype per decisori','entrepreneur|solo_pro','high','true'],
  ['fb_003','practical','Dove l\u2019AI sta gi\u00e0 facendo risparmiare tempo alle PMI','Casi operativi concreti','sme','high','true'],
  ['fb_004','practical','Cosa guardare davvero quando esce un nuovo tool AI','Criteri di valutazione veloci','solo_pro|sme','medium','true'],
  ['fb_005','practical','Gli errori pi\u00f9 comuni quando si prova a usare l\u2019AI in azienda','Anti-pattern da evitare','sme|entrepreneur','high','true'],
  ['fb_006','trend','Perch\u00e9 molte novit\u00e0 AI non cambiano nulla nel lavoro quotidiano','Punto di vista critico ma costruttivo','entrepreneur|solo_pro','medium','true'],
  ['fb_007','practical','Come trasformare una novit\u00e0 AI in vantaggio operativo concreto','Metodo step-by-step','sme|solo_pro','high','true']
];

return [{
  json: {
    spreadsheetId,
    missingSheets: missing,
    addRequests,
    headers: REQUIRED,
    seeds: {
      source_registry: SOURCE_ROWS,
      fallback_library: FALLBACK_ROWS
    }
  }
}];

// Build PUT value operations for all tabs: headers + seeds
const cfg = $('Plan Sheets').first().json;
const ops = [];
for (const [tab, cols] of Object.entries(cfg.headers)) {
  ops.push({ tab, range: `${tab}!A1`, values: [cols] });
  const seed = cfg.seeds[tab];
  if (seed && seed.length) {
    ops.push({ tab, range: `${tab}!A2`, values: seed });
  }
}
return ops.map(o => ({ json: { spreadsheetId: cfg.spreadsheetId, ...o } }));
